head.b:skin:
/* ============================================
   THE JOURNEY TOWARD REINTEGRATION
   Black / Grey / White Edition
   ============================================ */

/* --- Reset --- */
*, *::before, *::after {
  -webkit-box-sizing: border-box;
  -moz-box-sizing: border-box;
  box-sizing: border-box;
  margin: 0;
  padding: 0;
}

html {
  overflow-y: scroll;
}

body {
  background-color: #0d0d0d;
  color: #d0d0d0;
  font-family: 'IM Fell English', Georgia, serif;
  font-size: 16px;
  line-height: 1.85;
  -webkit-font-smoothing: antialiased;
  margin: 0;
  padding: 0;
}

a {
  color: #a0a0a0;
  text-decoration: none;
}

a:hover {
  color: #ffffff;
  text-decoration: none;
}

img {
  max-width: 100%;
  height: auto;
  display: block;
}

.section, .widget {
  margin: 0;
  padding: 0;
}

/* --- Outer Page Wrapper --- */
#outer-wrapper {
  width: 100%;
}

/* --- Inner content column --- */
.inner-col {
  width: 92%;
  max-width: 680px;
  margin-left: auto;
  margin-right: auto;
  padding-left: 16px;
  padding-right: 16px;
}

/* ============================================
   HEADER
   ============================================ */
#header-wrapper {
  width: 100%;
  background-color: #0d0d0d;
  border-bottom: 1px solid #333333;
  padding: 40px 16px 28px;
  text-align: center;
}

#header-wrapper .header-glyph {
  display: block;
  font-size: 1rem;
  color: #555555;
  letter-spacing: 0.5em;
  margin-bottom: 18px;
}

#header h1 {
  font-family: 'Cinzel Decorative', 'Palatino Linotype', serif;
  font-size: 28px;
  font-weight: 700;
  color: #ffffff;
  letter-spacing: 0.06em;
  line-height: 1.3;
  margin: 0 0 10px;
}

#header h1 a {
  color: #ffffff;
}

#header h1 a:hover {
  color: #cccccc;
}

#header .description {
  font-family: 'Cinzel', 'Palatino Linotype', serif;
  font-size: 11px;
  color: #666666;
  letter-spacing: 0.35em;
  text-transform: uppercase;
  margin-top: 8px;
}

/* ============================================
   NAVIGATION
   ============================================ */
#nav-wrapper {
  width: 100%;
  background-color: #111111;
  border-bottom: 1px solid #2a2a2a;
  padding: 14px 16px;
  text-align: center;
}

#nav-wrapper ul {
  list-style: none;
  list-style-type: none;
  margin: 0;
  padding: 0;
}

#nav-wrapper ul li {
  display: inline-block;
  margin: 0 14px;
}

#nav-wrapper ul li a {
  font-family: 'Cinzel', 'Palatino Linotype', serif;
  font-size: 11px;
  letter-spacing: 0.4em;
  text-transform: uppercase;
  color: #888888;
  border-bottom: 1px solid transparent;
  padding-bottom: 2px;
}

#nav-wrapper ul li a:hover {
  color: #ffffff;
  border-bottom-color: #555555;
}

/* ============================================
   ABOUT / INTRO
   ============================================ */
#about-wrapper {
  width: 100%;
  padding: 36px 16px 20px;
  text-align: center;
  border-bottom: 1px solid #1e1e1e;
}

#about-wrapper .widget-content {
  max-width: 560px;
  margin: 0 auto;
  font-style: italic;
  color: #666666;
  font-size: 15px;
  line-height: 1.9;
}

/* ============================================
   MAIN CONTENT WRAPPER
   ============================================ */
#main-wrapper {
  width: 100%;
}

#content-wrapper {
  width: 100%;
  padding: 40px 0 20px;
}

/* ============================================
   POST LIST â INDEX PAGE
   ============================================ */
.blog-posts .post-outer {
  width: 92%;
  max-width: 680px;
  margin: 0 auto 48px;
}

.blog-posts .post-outer + .post-outer {
  border-top: 1px solid #222222;
  padding-top: 48px;
}

.blog-posts .post-header {
  margin-bottom: 14px;
}

h2.date-header {
  font-family: 'Cinzel', serif;
  font-size: 10px;
  letter-spacing: 0.3em;
  text-transform: uppercase;
  color: #444444;
  margin-bottom: 10px;
  font-weight: normal;
  display: none;
}

.blog-posts h2.post-title {
  font-family: 'Cinzel', 'Palatino Linotype', serif;
  font-size: 22px;
  font-weight: 600;
  letter-spacing: 0.03em;
  line-height: 1.4;
  margin-bottom: 6px;
  margin-top: 0;
  color: #ffffff;
}

.blog-posts h2.post-title a {
  color: #ffffff;
}

.blog-posts h2.post-title a:hover {
  color: #cccccc;
}

.blog-posts .date-header {
  font-family: 'Cinzel', 'Palatino Linotype', serif;
  font-size: 10px;
  letter-spacing: 0.3em;
  text-transform: uppercase;
  color: #555555;
  display: block;
  margin-bottom: 8px;
}

/* POST BODY â index snippet */
.blog-posts .post-body {
  font-size: 15px;
  color: #b0b0b0;
  line-height: 1.9;
}

.blog-posts .post-body .jump-link {
  margin-top: 12px;
}

.blog-posts .post-body .jump-link a,
a.read-more {
  display: inline-block;
  font-family: 'Cinzel', 'Palatino Linotype', serif;
  font-size: 10px;
  letter-spacing: 0.4em;
  text-transform: uppercase;
  color: #888888;
  border-bottom: 1px solid #444444;
  padding-bottom: 1px;
}

.blog-posts .post-body .jump-link a:hover,
a.read-more:hover {
  color: #ffffff;
  border-bottom-color: #888888;
}

.blog-posts .post-footer {
  margin-top: 16px;
  font-family: 'Cinzel', 'Palatino Linotype', serif;
  font-size: 10px;
  letter-spacing: 0.25em;
  text-transform: uppercase;
  color: #444444;
}

.blog-posts .post-footer a {
  color: #555555;
}

.blog-posts .post-footer a:hover {
  color: #aaaaaa;
}

/* ============================================
   SINGLE POST â ITEM PAGE
   ============================================ */
.item-page .post-outer {
  width: 92%;
  max-width: 680px;
  margin: 0 auto;
  padding: 40px 0 20px;
}

.item-page h1.post-title {
  font-family: 'Cinzel Decorative', 'Palatino Linotype', serif;
  font-size: 26px;
  font-weight: 700;
  color: #ffffff;
  letter-spacing: 0.04em;
  line-height: 1.35;
  margin-bottom: 12px;
  margin-top: 0;
}

.item-page h1.post-title a {
  color: #ffffff;
}

.item-page .date-header {
  font-family: 'Cinzel', 'Palatino Linotype', serif;
  font-size: 10px;
  letter-spacing: 0.35em;
  text-transform: uppercase;
  color: #555555;
  display: block;
  margin-bottom: 20px;
}

.item-page .post-header {
  margin-bottom: 24px;
  padding-bottom: 20px;
  border-bottom: 1px solid #222222;
}

/* POST BODY â full post â THIS IS THE KEY FIX */
.item-page .post-body {
  font-size: 17px;
  line-height: 2;
  color: #cccccc;
}

.item-page .post-body p {
  margin-bottom: 1.4em;
  color: #cccccc;
}

.item-page .post-body h2,
.item-page .post-body h3,
.item-page .post-body h4 {
  font-family: 'Cinzel', 'Palatino Linotype', serif;
  color: #ffffff;
  margin: 2rem 0 0.75rem;
  letter-spacing: 0.05em;
  font-weight: 600;
}

.item-page .post-body h2 { font-size: 20px; }
.item-page .post-body h3 { font-size: 17px; }

.item-page .post-body blockquote {
  border-left: 2px solid #333333;
  margin: 1.75rem 0;
  padding: 0.5rem 0 0.5rem 1.5rem;
  color: #888888;
  font-style: italic;
}

.item-page .post-body a {
  color: #aaaaaa;
  border-bottom: 1px solid #444444;
}

.item-page .post-body a:hover {
  color: #ffffff;
  border-bottom-color: #888888;
}

.item-page .post-body ul,
.item-page .post-body ol {
  margin: 0 0 1.4em 1.5em;
  color: #cccccc;
}

.item-page .post-body li {
  margin-bottom: 0.5em;
}

.item-page .post-body img {
  margin: 1.5em 0;
  border: 1px solid #222222;
}

.item-page .post-footer {
  margin-top: 40px;
  padding-top: 20px;
  border-top: 1px solid #222222;
  font-family: 'Cinzel', 'Palatino Linotype', serif;
  font-size: 10px;
  letter-spacing: 0.3em;
  text-transform: uppercase;
  color: #444444;
}

.item-page .post-footer a {
  color: #555555;
}

.item-page .post-footer a:hover {
  color: #aaaaaa;
}

/* Share buttons */
.post-share-buttons {
  margin: 20px 0;
}

/* Reactions */
.reaction-buttons table {
  border: none;
  margin-bottom: 5px;
}

.reaction-buttons table,
.reaction-buttons td {
  border: none !important;
}

/* ============================================
   COMMENTS
   ============================================ */
#comments {
  width: 92%;
  max-width: 680px;
  margin: 40px auto 0;
  padding-bottom: 40px;
}

#comments h4 {
  font-family: 'Cinzel', 'Palatino Linotype', serif;
  font-size: 11px;
  letter-spacing: 0.4em;
  text-transform: uppercase;
  color: #555555;
  margin-bottom: 24px;
  padding-bottom: 12px;
  border-bottom: 1px solid #222222;
}

.comment-block {
  margin-bottom: 24px;
  padding-bottom: 24px;
  border-bottom: 1px solid #1e1e1e;
}

.comment-header {
  font-family: 'Cinzel', 'Palatino Linotype', serif;
  font-size: 10px;
  letter-spacing: 0.25em;
  text-transform: uppercase;
  color: #555555;
  margin-bottom: 8px;
}

.comment-content {
  font-size: 15px;
  color: #b0b0b0;
  line-height: 1.85;
}

.comment-footer {
  margin-top: 20px;
}

.comment-footer a {
  font-family: 'Cinzel', serif;
  font-size: 10px;
  letter-spacing: 0.3em;
  text-transform: uppercase;
  color: #666666;
}

.comment-footer a:hover {
  color: #aaaaaa;
}

/* ============================================
   PAGINATION
   ============================================ */
.blog-pager,
#blog-pager {
  width: 92%;
  max-width: 680px;
  margin: 0 auto;
  padding: 20px 0 48px;
  text-align: center;
  font-family: 'Cinzel', 'Palatino Linotype', serif;
  font-size: 10px;
  letter-spacing: 0.3em;
  text-transform: uppercase;
  color: #444444;
  overflow: hidden;
}

#blog-pager-newer-link { float: left; }
#blog-pager-older-link { float: right; }

.blog-pager a,
#blog-pager a {
  color: #666666;
  border-bottom: 1px solid transparent;
  padding-bottom: 2px;
}

.blog-pager a:hover,
#blog-pager a:hover {
  color: #ffffff;
  border-bottom-color: #555555;
}

.home-link {
  color: #444444 !important;
}

/* ============================================
   FEED LINKS
   ============================================ */
.feed-links {
  clear: both;
  font-family: 'Cinzel', serif;
  font-size: 10px;
  letter-spacing: 0.2em;
  text-transform: uppercase;
  color: #444444;
  text-align: center;
  padding: 10px 0;
}

.feed-links a {
  color: #555555;
}

.feed-links a:hover {
  color: #aaaaaa;
}

/* ============================================
   FOOTER
   ============================================ */
#footer-wrapper {
  width: 100%;
  border-top: 1px solid #1e1e1e;
  padding: 32px 16px 48px;
  text-align: center;
  margin-top: 20px;
}

#footer-wrapper .footer-line {
  font-family: 'Cinzel', 'Palatino Linotype', serif;
  font-size: 10px;
  letter-spacing: 0.35em;
  text-transform: uppercase;
  color: #444444;
  line-height: 2.2;
}

#footer-wrapper .footer-line a {
  color: #555555;
}

#footer-wrapper .footer-line a:hover {
  color: #aaaaaa;
}

/* ============================================
   SIDEBAR â hidden, required by Blogger
   ============================================ */
#sidebar-wrapper {
  display: none;
}

/* ============================================
   STATUS MESSAGES & MISC
   ============================================ */
.status-msg-wrap {
  padding: 10px;
  margin: 10px 0;
}

.deleted-comment {
  font-style: italic;
  color: #555555;
}

#navbar-iframe {
  height: 0;
  visibility: hidden;
  display: none;
}

.main .widget {
  margin: 0 0 5px;
  padding: 0;
}

.main .Blog {
  border-bottom-width: 0;
}

.section, .widget {
  margin: 0;
  padding: 0;
}

.widget-content {
  margin: 0;
  padding: 0;
}

.post-outer:first-child .date-header {
  margin-top: 0;
}

/* ============================================
   MOBILE â phones and small screens
   ============================================ */
@media only screen and (max-width: 640px) {

  #header-wrapper {
    padding: 28px 16px 20px;
  }

  #header h1 {
    font-size: 22px;
    letter-spacing: 0.03em;
  }

  #header .description {
    font-size: 10px;
    letter-spacing: 0.2em;
  }

  #nav-wrapper ul li {
    margin: 0 8px;
  }

  #nav-wrapper ul li a {
    font-size: 10px;
    letter-spacing: 0.25em;
  }

  #about-wrapper {
    padding: 24px 16px 16px;
  }

  #about-wrapper .widget-content {
    font-size: 14px;
  }

  #content-wrapper {
    padding: 28px 0 10px;
  }

  .blog-posts .post-outer {
    width: 94%;
    margin-bottom: 36px;
  }

  .blog-posts .post-outer + .post-outer {
    padding-top: 36px;
  }

  .blog-posts h2.post-title {
    font-size: 18px;
  }

  .blog-posts .post-body {
    font-size: 14px;
  }

  .item-page .post-outer {
    width: 94%;
    padding: 28px 0 10px;
  }

  .item-page h1.post-title {
    font-size: 20px;
  }

  .item-page .post-body {
    font-size: 15px;
    line-height: 1.9;
    color: #cccccc;
  }

  .item-page .post-body p {
    color: #cccccc;
  }

  #comments {
    width: 94%;
  }

  .blog-pager,
  #blog-pager {
    width: 94%;
    padding: 16px 0 36px;
  }

  #footer-wrapper {
    padding: 24px 16px 36px;
  }
/* ===== FIX BLOG CONTENT READABILITY ===== */

.post-body,
.post-body p,
.post-body span,
.post-body div {
  color: #e8e6e3 !important; /* soft white */
}

.post-body a {
  color: #c8a96e !important; /* your gold accent */
}

.post-title,
h1, h2, h3 {
  color: #ffffff !important;
}

/* Improve paragraph spacing for mobile */
.post-body p {
  line-height: 1.8;
  font-size: 1rem;
}

/* Optional: make meta text slightly visible */
.post-meta,
.date-header {
  color: #aaaaaa !important;
}
